const out = [];
const seen = new Set();

const stripFences = (raw) => {
  let txt = String(raw || '').replace(/^\uFEFF/, '').trim();
  if (txt.startsWith('```json')) txt = txt.slice(7);
  else if (txt.startsWith('```')) txt = txt.slice(3);
  if (txt.endsWith('```')) txt = txt.slice(0, -3);
  return txt.trim();
};

const fileHeaderRe = new RegExp('^\\s*\\/\\/\\s*file:\\s*.+\\.(ts|tsx|js|jsx|mjs|cjs)\\b', 'im');
const keywordRe = /\b(import|export|const|let|var|function|class|interface|type|async|await|if|return|try|catch|throw)\b/;
const narrativeRe = /^(deve|validar|implementar|criar|adicionar|ajustar|mudar|alterar)\b/i;

const parseMaybeJson = (raw) => {
  if (!raw || typeof raw !== 'string') return null;
  const txt = stripFences(raw);
  if (!txt) return null;
  try { return JSON.parse(txt); } catch (_e) { return null; }
};

const isLikelyCode = (value) => {
  const text = stripFences(value);
  if (!text || text.length < 40) return false;
  const hasFileHeader = fileHeaderRe.test(text);
  const hasKeyword = keywordRe.test(text);
  const hasSyntax = /[{}();=>]/.test(text);
  const narrativeOnly = narrativeRe.test(text) && !hasSyntax;
  return hasFileHeader && hasKeyword && hasSyntax && !narrativeOnly;
};

const pushRow = (items, changeId, code) => {
  const id = Number(changeId);
  const text = stripFences(code);
  if (!Number.isFinite(id) || !text || !isLikelyCode(text)) return;
  const key = id + '::' + text;
  if (seen.has(key)) return;
  seen.add(key);
  items.push({ change_id: id, code: text });
};

const rowsFromPayload = (payload, fallbackChangeId, suggestedCodes) => {
  const items = [];
  const cid = Number(fallbackChangeId);

  if (Array.isArray(payload)) {
    for (const row of payload) {
      if (row && typeof row === 'object') pushRow(items, row.change_id ?? cid, row.code ?? row.desc ?? row.description);
    }
  } else if (payload && typeof payload === 'object') {
    if (Array.isArray(payload.rows)) {
      for (const row of payload.rows) {
        if (row && typeof row === 'object') pushRow(items, row.change_id ?? cid, row.code ?? row.desc ?? row.description);
      }
    }
    if (Array.isArray(payload.code_changes)) {
      for (const code of payload.code_changes) pushRow(items, cid, code);
    }
  }

  if (items.length === 0 && Array.isArray(suggestedCodes)) {
    for (const code of suggestedCodes) pushRow(items, cid, code);
  }

  return items;
};

for (let i = 0; i < $input.all().length; i++) {
  const llm = $input.all()[i].json || {};
  let src = {};
  try { src = $item(i).$node['Build Code Change Rows'].json || {}; } catch (_e) { src = {}; }

  const raw = llm.text || llm.response?.text || llm.response || llm.choices?.[0]?.message?.content || '';
  const parsed = parseMaybeJson(raw);
  const rows = rowsFromPayload(parsed, src.change_id ?? llm.change_id, src.suggested_code_changes || []);
  for (const row of rows) out.push({ json: row });
}

return out;

